import { createAzure } from "@ai-sdk/azure";

export function getAzureOpenAI() {
  return createAzure({
    apiKey: process.env.AZURE_OPENAI_API_KEY!,
    resourceName: extractResourceName(process.env.AZURE_OPENAI_ENDPOINT!),
